import { Component, computed, inject, ViewChild } from '@angular/core';
import { MaCountry } from './country.model';
import { MatIcon } from '@angular/material/icon';
import { CreateCountryComponent } from '../../../components/create-country/create-country.component';
import { CommonModule } from '@angular/common';
import { CountryService } from './country.service';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input'
import { MatIconModule } from '@angular/material/icon';
import { MatLabel } from '@angular/material/form-field'
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatPaginator, MatPaginatorModule } from '@angular/material/paginator';
import { MatDialog, MatDialogConfig } from '@angular/material/dialog';
import { FormsModule } from '@angular/forms';
import { LoaderService } from '../../../shared/loader/loader.service';
import { LoaderComponent } from '../../../shared/loader/loader.component';

@Component({
  selector: 'app-country',
  standalone: true,
  imports: [MatFormFieldModule, MatInputModule, MatIconModule, MatIcon, CommonModule, MatPaginatorModule, MatTableModule, MatLabel, FormsModule,LoaderComponent],
  templateUrl: './country.component.html',
  styleUrl: './country.component.css'
})
export class CountryComponent {

  loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());
  isEditMode = false;
  pageSize = 100;
  currentPage = 0;
  totalItems = 0;
  searchTerm: string = '';
  displayedColumns: string[] = ['Sl.No', 'name', 'currency', 'status', 'Action'];
  dataSource = new MatTableDataSource<MaCountry>();
  @ViewChild(MatPaginator) paginator!: MatPaginator;

  constructor(private dialog: MatDialog, private countryService: CountryService) { }

  ngOnInit() {
    this.getMaCountryDataFromDb();
  }

  ngAfterViewInit() {
    this.dataSource.paginator = this.paginator;
  }


  onSearch(): void {
    this.dataSource.filter = this.searchTerm.trim().toLowerCase();
    if (this.dataSource.paginator) {
      this.dataSource.paginator.firstPage();
    }
  }

  // method to open the dialog in add mode
  openAddCountryDialog() {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
     const dialogRef = this.dialog.open(CreateCountryComponent, dialogConfig);
            dialogRef.afterClosed().subscribe((result) => {
              if (result === 'refresh') {
                this.getMaCountryDataFromDb();
              }
            });
  }

  // method to open the dialog in edit mode
  openEditCountryDialog(rowData: any) {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.data = { rowData };
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];
   const dialogRef = this.dialog.open(CreateCountryComponent, dialogConfig);
            dialogRef.afterClosed().subscribe((result) => {
              if (result === 'refresh') {
                this.getMaCountryDataFromDb();
              }
            });


  }

//   onPaginateChange(event: any) {
//     console.log("event.pageSize", event.pageSize, "event.pageIndex",event.pageIndex);
//   this.pageSize = event.pageSize;
//   this.currentPage = event.pageIndex;
//   this.getMaCountryDataFromDb();
// }

  getMaCountryDataFromDb() {
    const body = {
      page:  1,
      page_size: 100,
      query:'',
      status: "Y"
    }
    this.loader.show();
    this.countryService.CountryDataFromDb(body).subscribe({
      next: (response: MaCountry[]) => {
        this.dataSource = new MatTableDataSource(response);
         this.dataSource.filterPredicate = (data: MaCountry, filter: string): boolean => {
                 return (data.name ?? '').toLowerCase().includes(filter);
              };
        
        this.dataSource.paginator = this.paginator;
        this.loader.hide();
      },
      error: (err) => {
        console.error('Error fetching countries:', err);
        this.loader.hide();
      }
    });
  }

}
