import { Component, computed, inject, Inject } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { ReactiveFormsModule } from '@angular/forms';
import { MatSelect, MatOption } from '@angular/material/select';
import { CountryService } from '../../pages/master/country/country.service';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input'
import { MatIconModule } from '@angular/material/icon';
import { MatLabel } from '@angular/material/form-field';
import { CommonModule } from '@angular/common';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import { LoaderService } from '../../shared/loader/loader.service';
import { allowOnlyLetters } from '../../pages/master/master.utils';
import { MatSnackBarModule } from '@angular/material/snack-bar';
import { SnackbarService } from '../../shared/snack-bar/snack-bar.service';
import { LoaderComponent } from '../../shared/loader/loader.component';


@Component({
  selector: 'app-create-country',
  standalone: true,
  imports: [MatFormFieldModule,
    MatLabel, MatIconModule, MatFormFieldModule, MatInputModule, ReactiveFormsModule, MatSelect, MatOption, CommonModule, MatSlideToggleModule, MatSnackBarModule, LoaderComponent],
  templateUrl: './create-country.component.html',
  styleUrls: ['./create-country.component.css']
})
export class CreateCountryComponent {
  private loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());
  disallowNumericData = allowOnlyLetters;
  countryForm: FormGroup;
  isEditMode = false;
  constructor(
    private fb: FormBuilder,
    private dialogRef: MatDialogRef<CreateCountryComponent>,
    @Inject(MAT_DIALOG_DATA) public existingdata: any,
    private countryService: CountryService,
    private snackBar: SnackbarService
  ) {
    const data = existingdata?.rowData;
    this.isEditMode = !!data;
    this.countryForm = this.fb.group({
      country_id: [data?.country_id || 0],
      name: [data?.name || '', [Validators.required, Validators.maxLength(50), Validators.pattern('^[A-Za-z\\s]+$')]],
      currency: [data?.currency || '', Validators.required],
      status: [data?.status === 'Inactive' ? false : true],

    });
  }

  onSubmit() {
    if (this.countryForm.valid) {
      this.loader.show();
      this.countryService.CountryDataToDB(this.countryForm.value).subscribe({
        next: (res) => {
          this.loader.hide();
          this.snackBar.showSuccess(res.message);
          this.dialogRef.close("refresh");
        },
        error: (error) => {
          this.loader.hide();
          const errorMsg = error.error?.detail || 'Something went wrong. Please try again.';
          this.snackBar.showError(errorMsg);
        }
      })
    }
  }
  allowSpecialCharacters(event: KeyboardEvent): boolean {
    const pattern = /^[A-Za-z\s@._$!#%^&*-]+$/;
    const char = String.fromCharCode(event.keyCode || event.which);
    return pattern.test(char);
  }

  closeDialog() {
    this.dialogRef.close();
  }
}
